class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

def split_circular_list(head: Node) -> (Node, Node):
    if not head:
        return None, None

    if head.next == head:
        return head, None

    slow = head
    fast = head.next

    while fast != head and fast.next != head:
        slow = slow.next
        fast = fast.next.next

    head_1 = head
    head_2 = slow.next

    slow.next = head_1

    current_second_half_end = head_2
    while current_second_half_end.next != head_1:
        current_second_half_end = current_second_half_end.next

    current_second_half_end.next = head_2

    return head_1, head_2
